mapper.select:
select * from ygt_campaign_goods
and ygt_cg_campaign_id = #{campaignId}
order by ygt_cg_sort asc, ygt_campaign_goods_id asc
limit #{offset}, #{limit}

mapper.update:
update ygt_campaign_goods
ygt_cg_goods_name_snapshot = #{ygtCgGoodsNameSnapshot}, ygt_cg_standard_snapshot = #{ygtCgStandardSnapshot}, ygt_cg_unit_snapshot = #{ygtCgUnitSnapshot}, ygt_cg_price_snapshot = #{ygtCgPriceSnapshot}, ygt_cg_sort = #{ygtCgSort}, ygt_cg_status = #{ygtCgStatus}, ygt_cg_update_time = now()
where ygt_campaign_goods_id = #{ygtCampaignGoodsId}
